import{_ as e,a as t,b as o,c as a,d as r,e as i,f as n,g as s}from"./chunks/asktug_mva.6abe5238.js";import{_ as l,c,o as h,N as d}from"./chunks/framework.0799945b.js";const v=JSON.parse('{"title":"数巢DBNEST","description":"","frontmatter":{},"headers":[],"relativePath":"en/index.md"}'),p={name:"en/index.md"},g=d('<h1 id="数巢dbnest" tabindex="-1">数巢DBNEST <a class="header-anchor" href="#数巢dbnest" aria-label="Permalink to &quot;数巢DBNEST&quot;">​</a></h1><p>Jan&#39;s Blog Introduction</p><p><img src="'+e+'" alt="header"></p><ul><li>Bilibili: <a href="https://space.bilibili.com/318184941?spm_id_from=333.1007.0.0" target="_blank" rel="noreferrer">JanDBNest</a></li><li>technology blog: <a href="http://www.dbnest.net/zh/tidb/07TiDB-%E6%BA%90%E7%A0%81%E9%98%85%E8%AF%BB/8-1TiDB/02TiDB%20Point_Get%20%E7%82%B9%E6%9F%A5%E7%9A%84%E4%B8%80%E7%94%9F.html" target="_blank" rel="noreferrer">The lifetime of TiDB Point_Get</a></li><li>Github: <a href="https://github.com/jansu-dev" target="_blank" rel="noreferrer">https://github.com/jansu-dev</a></li><li>Email: <a href="mailto:jan-su-dev@outlook.com" target="_blank" rel="noreferrer">jan-su-dev@outlook.com</a></li><li>Wechat: xh9836 <code>(Please state your purpose and where get my info)</code></li></ul><h2 id="blog-content" tabindex="-1">Blog content <a class="header-anchor" href="#blog-content" aria-label="Permalink to &quot;Blog content&quot;">​</a></h2><ol><li><strong>What</strong>: mainly records of personal knowledge database in <strong>TiDB Series</strong>,<strong>Oracle Series</strong>, <strong>English Learning notes</strong>, and <strong>worth sharing content</strong>.</li><li><strong>Why</strong>: Hope in the form of blog, to overcome my own forgetting, and to like-minded partners to provide information, and also correct my own mistakes in my notes.</li><li><strong>How</strong>: In the navigation bar <strong>&quot;Docs&quot;</strong>, record the learning process, also welcome everyone to leave your comments and questions in <strong>&quot;community&quot;</strong>.</li></ol><h2 id="technical-origin" tabindex="-1">Technical origin <a class="header-anchor" href="#technical-origin" aria-label="Permalink to &quot;Technical origin&quot;">​</a></h2><ol><li><p>When I was in junior high school, I read a book called <code>Jack Ma&#39;s Entrepreneurial Revelation</code> (PS: Although the content in the book has little to do with technology), which made me see the changes that the Internet has brought to China. Subsequently, I also opened several online stores and earned some pocket money 😁, which led to my resolute decision to major in IT when I was in college. During my college years, I assisted teachers in using <strong>Python + Scrapy + chrome-driver + phantomjs</strong> to obtain Boss Zhiping, 51 job and other information for analysis, and the direction of school curriculum reform matched the market demand.</p></li><li><p>Upon graduation, I entered the database industry at the recommendation of my teacher. When I first entered the industry, I chose Oracle, which was stable and surrounded by sound ecology, to study. However, I worked as a database administrator (DBA) at that time. Personally, I think I should go deep into the database (code layer) to learn more about it. Just like <strong>&#39;What I cannot create, I do not understand.&#39; -- Richard Phillips Feynman</strong> said, cannot make cannot really understand. Then had the opportunity to come to work <a href="https://baike.baidu.com/item/PingCAP/60056692?fr=aladdin" target="_blank" rel="noreferrer">PingCAP</a>, learning a new generation of distributed HTAP database.</p></li><li><p>Follow the idea of in-depth kernel learning, and gradually get to know Golang, Rust, NodeJs and other languages in the process. The technology road is very interesting and is an important force to push the world forward.</p></li></ol><hr><h2 id="open-source-projects" tabindex="-1">Open source projects <a class="header-anchor" href="#open-source-projects" aria-label="Permalink to &quot;Open source projects&quot;">​</a></h2><p>(Nothing is more convincing to a programmer than Show me the code.)</p><ul><li><p><a href="https://github.com/jansu-dev/tihc" target="_blank" rel="noreferrer">TiHC</a> : TiHC (TiDB Healthy Check) is an open source, RUst-built TiDB inspection tool designed to reduce inquiry times and improve delivery efficiency. Based on the principle of ssh distribution by TiDB official tool tiup, distributed collection of node information and grafana monitoring were integrated to generate a deliverable inspection Office Doc file.</p></li><li><p><a href="https://github.com/jansu-dev/mbr" target="_blank" rel="noreferrer">MBR</a> : The MBR(MicroBR) is a small toy built by Rust and mimics some functions of the TiDB BR. It implements some interfaces and functions of the TiDB physical backup tool.</p></li></ul><h2 id="technical-articles" tabindex="-1">Technical articles <a class="header-anchor" href="#technical-articles" aria-label="Permalink to &quot;Technical articles&quot;">​</a></h2><ul><li><a href="https://tidb.net/blog/d6444c63" target="_blank" rel="noreferrer">SQL PointGet&#39;s life: TiDB point to check how to pass the mysql protocol, parser, compile, executor, the scheduler module processing</a></li><li><a href="https://tidb.net/blog/70588c4c" target="_blank" rel="noreferrer">TiCDC series share: background and using situation</a></li><li><a href="https://tidb.net/blog/9568ace1" target="_blank" rel="noreferrer">TiCDC series sharing: to analyze the synchronization model and the basic architecture</a></li></ul><hr><h2 id="video-speech" tabindex="-1">Video speech <a class="header-anchor" href="#video-speech" aria-label="Permalink to &quot;Video speech&quot;">​</a></h2><ol><li><a href="https://asktug.com/t/topic/998896#h-2" target="_blank" rel="noreferrer">【2022年】TiDB 社区年度总结 - 版主 - 苏志鹏（jansu-dev）</a></li></ol><hr><h2 id="certificate-honors" tabindex="-1">Certificate honors <a class="header-anchor" href="#certificate-honors" aria-label="Permalink to &quot;Certificate honors&quot;">​</a></h2><ol><li><p>Oracle OCP <img src="'+t+'" alt="oracle_ocp"></p></li><li><p>TiDB PTCP(chinese version) <img src="'+o+'" alt="tidb_ptcp_chinest"></p></li><li><p>TiDB PTCA(english/global version 6) <img src="'+a+'" alt="tidb_ptca_global"></p></li><li><p>TiDB PTCP(english/global version 6) <img src="'+r+'" alt="tidb_ptcp_global"></p></li><li><p>PostgreSQL PGCA <img src="'+i+'" alt="pg_pgca"></p></li><li><p>PostgreSQL PGCE <img src="'+n+'" alt="pg_pgce"></p></li><li><p>AskTUG MVA: <a href="https://asktug.com/t/topic/273501" target="_blank" rel="noreferrer">related link</a><img src="'+s+'" alt="asktug_mva"></p></li></ol><hr><p>About life</p><p>About website</p><p>网站备案号<a href="https://beian.miit.gov.cn" target="_blank" rel="noreferrer">（ 辽ICP备19006373号-3）</a></p>',24),m=[g];function u(b,f,_,k,y,T){return h(),c("div",null,m)}const w=l(p,[["render",u]]);export{v as __pageData,w as default};
